// TestClaudeRunnerHarnessConformance asserts the bare Harness contract.
// Run in an isolated env: a non-existent cache path and an empty PATH
// so neither a stale snapshot nor a real claude binary can sneak in.
func TestClaudeRunnerHarnessConformance(t *testing.T) {
	isolateClaudeRunnerEnv(t)
	harnesstest.RunHarnessConformance(t, &claude.Runner{})
}

// TestClaudeRunnerQuotaHarnessConformance asserts QuotaHarness contract:
// QuotaStatus returns a valid value with no error for a cold cache;
// RefreshQuota's probe failure surfaces as State=QuotaUnavailable on a
// valid status value, not as an error.
func TestClaudeRunnerQuotaHarnessConformance(t *testing.T) {
	isolateClaudeRunnerEnv(t)
	harnesstest.RunQuotaHarnessConformance(t, &claude.Runner{})
}

// TestClaudeRunnerAccountHarnessConformance asserts the AccountHarness
// contract against the cold-cache path (no embedded account evidence).
func TestClaudeRunnerAccountHarnessConformance(t *testing.T) {
	isolateClaudeRunnerEnv(t)
	harnesstest.RunAccountHarnessConformance(t, &claude.Runner{})
}

// TestClaudeRunnerModelDiscoveryHarnessConformance asserts ResolveModelAlias
// covers each documented family and rejects out-of-set families with
// ErrAliasNotResolvable.
func TestClaudeRunnerModelDiscoveryHarnessConformance(t *testing.T) {
	isolateClaudeRunnerEnv(t)
	harnesstest.RunModelDiscoveryHarnessConformance(t, &claude.Runner{})
}

// isolateClaudeRunnerEnv points the quota cache at a temp file that
// doesn't exist and clears PATH so the PTY probe cannot find a real
// claude binary. This is the cold-cache + binary-absent path the
// CONTRACT-004 conformance suite expects on every harness.
func isolateClaudeRunnerEnv(t *testing.T) {
	t.Helper()
	dir := t.TempDir()
	t.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", filepath.Join(dir, "claude-quota.json"))
	t.Setenv("PATH", "")
}

func TestHealthCheck_ClaudeRefreshesQuotaWhenStale(t *testing.T) {
	dir := t.TempDir()
	cachePath := filepath.Join(dir, "claude-quota.json")
	t.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", cachePath)

	// Write a snapshot older than the 15m debounce.
	staleSnap := claudeTestQuotaSnapshot{
		CapturedAt:        time.Now().UTC().Add(-20 * time.Minute),
		FiveHourRemaining: 80,
		FiveHourLimit:     100,
		WeeklyRemaining:   90,
		WeeklyLimit:       100,
		Source:            "pty",
	}
	writeClaudeQuotaCacheFile(t, cachePath, staleSnap)

	// Inject a fake refresher so no real PTY probe is invoked.
	refreshCalled := false
	setClaudeQuotaRefresherForTest(t, func(timeout time.Duration) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
		refreshCalled = true
		return []harnesses.QuotaWindow{
			{LimitID: "session", UsedPercent: 20},
			{LimitID: "weekly-all", UsedPercent: 10},
		}, nil, nil
	})

	svc := newTestService(t, ServiceOptions{})
	// HealthCheck for "claude" requires the binary to be discoverable.
	// If claude is not in PATH, the harness is unavailable → the quota refresh
	// is never reached. To keep the test self-contained we call the helper
	// directly rather than going through HealthCheck's availability gate.
	svc.healthCheckRefreshClaudeQuota(context.Background())

	if !refreshCalled {
		t.Error("expected healthCheckClaudeQuotaRefresher to be called for stale cache")
	}

	// Verify the cache was rewritten with a newer timestamp.
	loaded, ok := readClaudeQuotaCacheFile(t, cachePath)
	if !ok {
		t.Fatal("expected cache file to exist after refresh")
	}
	if !loaded.CapturedAt.After(staleSnap.CapturedAt) {
		t.Errorf("expected cache CapturedAt to be newer than stale snapshot: got %v, stale was %v",
			loaded.CapturedAt, staleSnap.CapturedAt)
	}
}

// TestHealthCheck_ClaudeSkipsRefreshWhenFresh verifies that HealthCheck does
// NOT invoke the PTY quota refresher when the cached snapshot is younger than
// default quota refresh debounce (15m).
func TestHealthCheck_ClaudeSkipsRefreshWhenFresh(t *testing.T) {
	dir := t.TempDir()
	cachePath := filepath.Join(dir, "claude-quota.json")
	t.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", cachePath)

	// Write a snapshot that is only 30s old (fresh).
	freshSnap := claudeTestQuotaSnapshot{
		CapturedAt:        time.Now().UTC().Add(-30 * time.Second),
		FiveHourRemaining: 80,
		FiveHourLimit:     100,
		WeeklyRemaining:   90,
		WeeklyLimit:       100,
		Source:            "pty",
		Account:           &harnesses.AccountInfo{PlanType: "Claude Max"},
	}
	writeClaudeQuotaCacheFile(t, cachePath, freshSnap)

	// Inject a fake refresher that must NOT be called.
	refreshCalled := false
	setClaudeQuotaRefresherForTest(t, func(timeout time.Duration) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
		refreshCalled = true
		return nil, nil, nil
	})

	svc := newTestService(t, ServiceOptions{})
	svc.healthCheckRefreshClaudeQuota(context.Background())

	if refreshCalled {
		t.Error("expected healthCheckClaudeQuotaRefresher NOT to be called for fresh cache")
	}

	// Verify the cache timestamp is unchanged (still matches freshSnap).
	loaded, ok := readClaudeQuotaCacheFile(t, cachePath)
	if !ok {
		t.Fatal("expected cache file to still exist")
	}
	if !loaded.CapturedAt.Equal(freshSnap.CapturedAt) {
		t.Errorf("cache was unexpectedly rewritten: got CapturedAt %v, want %v",
			loaded.CapturedAt, freshSnap.CapturedAt)
	}
}

