func (f *fakeClaudeQuotaHarness) AccountStatus(ctx context.Context, now time.Time) (harnesses.AccountSnapshot, error) {
	if err := ctx.Err(); err != nil {
		return harnesses.AccountSnapshot{}, err
	}
	status, err := f.QuotaStatus(ctx, now)
